#!/usr/bin/env node
/**
 * Renders the two brand rasters this repo needs beyond what the logo kit already ships
 * (assets/brand/generated — regenerated by its own Python script, see assets/brand/README.md):
 *
 *  - apps/desktop/resources/tray-{green,red}.png — the tray glyph tinted per USB-key state.
 *  - apps/web/public/og-default.png — the 1200x630 social card referenced by the web metadata.
 *
 * Regeneration only; the outputs are committed. Requires a local Chrome/Chromium because the repo
 * has no native rasteriser.
 *
 *   node scripts/generate-brand-rasters.mjs
 */

import { execFileSync } from "node:child_process";
import { mkdtempSync, readFileSync, rmSync, writeFileSync } from "node:fs";
import { tmpdir } from "node:os";
import { dirname, resolve } from "node:path";
import { fileURLToPath } from "node:url";

const root = resolve(dirname(fileURLToPath(import.meta.url)), "..");
const brand = resolve(root, "assets/brand");

// Matches assets/brand/source/brand-tokens.json.
const INK = "#08090a";
const SUCCESS = "#22c55e";
const DANGER = "#ef4444";

const TRAY_SIZE = 32;

const CHROME_CANDIDATES = [
  process.env.CHROME_PATH,
  "google-chrome",
  "chromium",
  "chromium-browser",
  "google-chrome-stable",
].filter(Boolean);

function findChrome() {
  for (const candidate of CHROME_CANDIDATES) {
    try {
      execFileSync(candidate, ["--version"], { stdio: "ignore" });
      return candidate;
    } catch {
      // Try the next candidate.
    }
  }
  throw new Error(
    `No Chrome/Chromium found (tried: ${CHROME_CANDIDATES.join(", ")}). Set CHROME_PATH.`,
  );
}

const chrome = findChrome();
const work = mkdtempSync(resolve(tmpdir(), "talysman-brand-"));

/** Screenshots an HTML document at an exact size. `transparent` keeps the alpha channel. */
function shoot({ name, html, width, height, out, transparent = false }) {
  const page = resolve(work, `${name}.html`);
  writeFileSync(page, html);
  execFileSync(
    chrome,
    [
      "--headless",
      "--disable-gpu",
      "--hide-scrollbars",
      ...(transparent ? ["--default-background-color=00000000"] : []),
      `--screenshot=${resolve(root, out)}`,
      `--window-size=${width},${height}`,
      `file://${page}`,
    ],
    { stdio: "ignore" },
  );
  console.log(`wrote ${out} (${width}x${height})`);
}

// --- Tray icons -----------------------------------------------------------------------------
// The glyph is authored with `color:` on the root <svg> and painted via `currentColor`, so a tint
// is a style override rather than a second source file.
const traySvg = readFileSync(resolve(brand, "source/talysman-tray.svg"), "utf8");

function tinted(color) {
  const out = traySvg.replace(/style="color:[^"]*"/, `style="color:${color}"`);
  if (out === traySvg) throw new Error("tray svg no longer carries a root color style");
  return out;
}

for (const [file, color] of [
  ["tray-green.png", SUCCESS],
  ["tray-red.png", DANGER],
]) {
  shoot({
    name: file,
    width: TRAY_SIZE,
    height: TRAY_SIZE,
    transparent: true,
    out: `apps/desktop/resources/${file}`,
    html:
      `<!doctype html><meta charset="utf-8">` +
      `<style>html,body{margin:0;padding:0;background:transparent}` +
      `svg{display:block;width:${TRAY_SIZE}px;height:${TRAY_SIZE}px}</style>` +
      tinted(color),
  });
}

// --- Open Graph card ------------------------------------------------------------------------
// The tagline lockup centred on the brand background, at the 1200x630 social-card size.
const lockup = readFileSync(
  resolve(brand, "generated/master/talysman-lockup-tagline-1740x620.png"),
).toString("base64");

shoot({
  name: "og-default",
  width: 1200,
  height: 630,
  out: "apps/web/public/og-default.png",
  html:
    `<!doctype html><meta charset="utf-8">` +
    `<style>html,body{margin:0;height:100%;background:${INK}}` +
    `body{display:flex;align-items:center;justify-content:center}` +
    // The master lockup canvas carries more padding below the tagline than above the mark, so
    // centring the file leaves the artwork visually high. Nudge it back onto the optical centre.
    `img{width:900px;transform:translateY(28px)}</style>` +
    `<img src="data:image/png;base64,${lockup}" alt="">`,
});

rmSync(work, { recursive: true, force: true });
